import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import AdminLayout from '../../components/AdminLayout';
import { ArrowLeft, Save, Package, Calendar, CheckCircle2, Search, X, Loader2 } from 'lucide-react';
import api from '../../services/api';
import { useToast } from '../../components/Toast';

const AdminBulkAssign = () => {
  const navigate = useNavigate();
  const { clientId } = useParams(); // If editing a specific client's assignments
  const { showSuccess, showError } = useToast();

  const CLIENT_PAGE_SIZE = 40;

  const [loading, setLoading] = useState(true);
  const [clientsLoading, setClientsLoading] = useState(true);   // first page / search
  const [clientsLoadingMore, setClientsLoadingMore] = useState(false); // "Load more"
  const [saving, setSaving] = useState(false);
  const [tools, setTools] = useState([]);
  const [clients, setClients] = useState([]);          // accumulated, paged client list
  const [clientPage, setClientPage] = useState(1);
  const [clientHasMore, setClientHasMore] = useState(false);
  const [clientTotal, setClientTotal] = useState(0);
  const [selectedTools, setSelectedTools] = useState([]);
  const [selectedClients, setSelectedClients] = useState([]);
  const [toolSearch, setToolSearch] = useState('');
  const [clientSearch, setClientSearch] = useState('');
  const [duration, setDuration] = useState(() => {
    // Default to the "1 Month" preset WITH a real endDate so an admin can assign
    // immediately without first touching the duration controls (otherwise the empty
    // endDate fails validation and the assign silently does nothing).
    const start = new Date();
    const end = new Date();
    end.setDate(end.getDate() + 30);
    return {
      startDate: start.toISOString().split('T')[0],
      endDate: end.toISOString().split('T')[0],
      preset: '30',
    };
  });

  useEffect(() => {
    loadInitial();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Server-side client search (debounced) so the picker can reach EVERY client —
  // the search hits the DB (name OR email), not just the rows already loaded. Each
  // new term resets to page 1. Selections persist across searches/pages (they live
  // in selectedClients, independent of the loaded list).
  useEffect(() => {
    const t = setTimeout(() => { loadClients(clientSearch, 1, false); }, 300);
    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [clientSearch]);

  const loadClients = async (search = '', page = 1, append = false) => {
    try {
      append ? setClientsLoadingMore(true) : setClientsLoading(true);
      const params = new URLSearchParams({
        status: 'active',
        page: String(page),
        limit: String(CLIENT_PAGE_SIZE),
      });
      if (search.trim()) params.append('search', search.trim());
      const res = await api.get(`/admin/clients?${params}`);
      const list = res.data.clients || [];
      const pg = res.data.pagination || {};
      setClients(prev => (append ? [...prev, ...list] : list));
      setClientPage(pg.page || page);
      setClientHasMore(typeof pg.hasMore === 'boolean' ? pg.hasMore : list.length === CLIENT_PAGE_SIZE);
      setClientTotal(typeof pg.totalCount === 'number' ? pg.totalCount : list.length);
    } catch (_) {
      // Best-effort: keep whatever was already loaded so the picker never goes blank.
    } finally {
      append ? setClientsLoadingMore(false) : setClientsLoading(false);
    }
  };

  const loadMoreClients = () => loadClients(clientSearch, clientPage + 1, true);

  const loadInitial = async () => {
    try {
      setLoading(true);
      const toolsRes = await api.get('/admin/tools?limit=100');
      setTools(toolsRes.data.tools?.filter(t => t.status === 'active') || []);

      // Pre-select the scoped client by id — fetched directly so it always resolves
      // (with name + email) even if it falls outside the first page of the list.
      if (clientId) {
        try {
          const r = await api.get(`/admin/clients/${clientId}`);
          if (r.data?.client) setSelectedClients([r.data.client]);
        } catch (_) { /* client may have been removed — leave unselected */ }
      }
    } catch (error) {
      showError('Failed to load data');
    } finally {
      setLoading(false);
    }
    // Clients load via the debounced search effect (fires once on mount with no term).
  };

  const handlePresetChange = (days) => {
    setDuration(prev => {
      const start = new Date(prev.startDate);
      const end = new Date(start);
      end.setDate(end.getDate() + parseInt(days));
      return {
        ...prev,
        preset: days,
        endDate: end.toISOString().split('T')[0]
      };
    });
  };

  const toggleClient = (client) => {
    setSelectedClients(prev => {
      const isSelected = prev.some(c => c._id === client._id);
      if (isSelected) {
        return prev.filter(c => c._id !== client._id);
      }
      return [...prev, client];
    });
  };

  const selectAllClients = () => {
    const filtered = filteredClients;
    const allSelected = filtered.every(c => selectedClients.some(s => s._id === c._id));
    if (allSelected) {
      setSelectedClients(prev => prev.filter(c => !filtered.some(f => f._id === c._id)));
    } else {
      setSelectedClients(prev => {
        const newClients = filtered.filter(c => !prev.some(p => p._id === c._id));
        return [...prev, ...newClients];
      });
    }
  };

  const toggleTool = (tool) => {
    setSelectedTools(prev =>
      prev.some(t => t._id === tool._id)
        ? prev.filter(t => t._id !== tool._id)
        : [...prev, tool]
    );
  };

  const selectAllTools = () => {
    const filtered = filteredTools;
    const allSelected = filtered.length > 0 && filtered.every(t => selectedTools.some(s => s._id === t._id));
    if (allSelected) {
      setSelectedTools(prev => prev.filter(t => !filtered.some(f => f._id === t._id)));
    } else {
      setSelectedTools(prev => [...prev, ...filtered.filter(t => !prev.some(p => p._id === t._id))]);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (selectedTools.length === 0) {
      showError('Please select at least one tool');
      return;
    }

    if (selectedClients.length === 0) {
      showError('Please select at least one client');
      return;
    }

    if (!duration.startDate || !duration.endDate) {
      showError('Please set access duration');
      return;
    }

    try {
      setSaving(true);

      const clientIds = selectedClients.map(c => c._id);
      // The bulk endpoint assigns ONE tool to many clients; loop the selected tools
      // so we can assign multiple tools to the same set of clients in one action.
      const results = await Promise.allSettled(
        selectedTools.map(tool =>
          api.post('/admin/assignments/bulk', {
            toolId: tool._id,
            clientIds,
            startDate: duration.startDate,
            endDate: duration.endDate
          })
        )
      );

      const ok = results.filter(r => r.status === 'fulfilled').length;
      const failed = results.length - ok;

      if (ok > 0) {
        showSuccess(
          `Assigned ${ok} tool${ok === 1 ? '' : 's'} to ${selectedClients.length} client${selectedClients.length === 1 ? '' : 's'}` +
          (failed ? ` — ${failed} failed` : '')
        );
        navigate('/admin/clients');
      } else {
        const firstErr = results.find(r => r.status === 'rejected');
        showError(firstErr?.reason?.response?.data?.error || 'Failed to assign tools');
      }
    } catch (error) {
      showError(error.response?.data?.error || 'Failed to assign tools');
    } finally {
      setSaving(false);
    }
  };

  const filteredTools = tools.filter(t =>
    t.name.toLowerCase().includes(toolSearch.toLowerCase())
  );

  // Search is performed server-side (by name OR email) in loadClients, so the fetched
  // list is already the matching set — no client-side re-filtering needed.
  const filteredClients = clients;

  // Compact step header
  const StepHead = ({ n, title, children }) => (
    <div className="flex items-center gap-2.5 mb-3">
      <div className="w-7 h-7 rounded-lg flex items-center justify-center text-white font-bold text-sm flex-shrink-0"
           style={{ background: 'var(--gradient-cta)' }}>{n}</div>
      <h2 className="text-base font-bold text-genz-navy">{title}</h2>
      {children}
    </div>
  );

  if (loading) {
    return (
      <AdminLayout>
        <div className="flex items-center justify-center min-h-[80vh]">
          <div className="animate-spin rounded-full h-12 w-12 border-4 border-genz-teal border-t-transparent"></div>
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout>
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        {/* Header */}
        <div className="mb-5">
          <button
            onClick={() => navigate('/admin/clients')}
            className="flex items-center gap-1.5 text-sm text-genz-muted hover:text-genz-navy transition-colors mb-3"
          >
            <ArrowLeft size={16} />
            Back to Clients
          </button>
          <h1 className="text-2xl font-extrabold text-genz-navy">Assign Tools</h1>
          <p className="text-sm text-genz-muted mt-1">Assign one or more tools to one or more clients at once</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Step 1: Select Tool */}
          <div className="ds-card p-4">
            <StepHead n={1} title="Select Tools">
              <span className="ds-badge ds-badge-teal">{selectedTools.length} selected</span>
              {filteredTools.length > 0 && (
                <button
                  type="button"
                  onClick={selectAllTools}
                  className="ml-auto text-sm font-medium text-genz-teal hover:underline"
                >
                  {filteredTools.every(t => selectedTools.some(s => s._id === t._id)) ? 'Deselect All' : 'Select All'}
                </button>
              )}
            </StepHead>

            <div className="relative mb-3">
              <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-genz-muted" size={16} />
              <input
                type="text"
                placeholder="Search tools..."
                value={toolSearch}
                onChange={(e) => setToolSearch(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 text-sm bg-genz-bg border border-genz-border rounded-xl text-genz-navy placeholder-genz-muted focus:outline-none focus:border-genz-teal transition-colors"
              />
            </div>

            {/* Selected tools as removable chips */}
            {selectedTools.length > 0 && (
              <div className="flex flex-wrap gap-1.5 mb-3 p-2.5 bg-genz-bg rounded-xl">
                {selectedTools.map(tool => (
                  <span
                    key={tool._id}
                    className="inline-flex items-center gap-1 px-2.5 py-1 bg-genz-teal/20 text-genz-teal text-xs font-medium rounded-full max-w-full"
                  >
                    <span className="truncate max-w-[200px]">{tool.name}</span>
                    <button type="button" onClick={() => toggleTool(tool)} className="hover:text-genz-navy flex-shrink-0" aria-label={`Remove ${tool.name}`}>
                      <X size={12} />
                    </button>
                  </span>
                ))}
              </div>
            )}

            <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2 max-h-56 overflow-y-auto pr-1">
              {filteredTools.map(tool => {
                const isSelected = selectedTools.some(t => t._id === tool._id);
                return (
                  <button
                    key={tool._id}
                    type="button"
                    onClick={() => toggleTool(tool)}
                    className={`flex items-center gap-2 px-3 py-2.5 rounded-lg border text-left transition-all ${
                      isSelected
                        ? 'border-genz-teal bg-genz-teal/10'
                        : 'border-genz-border bg-genz-bg hover:border-genz-teal/50'
                    }`}
                    data-testid={`select-tool-${tool._id}`}
                  >
                    <Package size={16} className={`flex-shrink-0 ${isSelected ? 'text-genz-teal' : 'text-genz-muted'}`} />
                    <span className="text-sm font-medium text-genz-navy truncate flex-1">{tool.name}</span>
                    {isSelected && <CheckCircle2 size={14} className="text-genz-teal flex-shrink-0" />}
                  </button>
                );
              })}
            </div>

            {filteredTools.length === 0 && (
              <p className="text-center text-sm text-genz-muted py-3">No active tools found</p>
            )}
          </div>

          {/* Step 2: Select Clients */}
          <div className="ds-card p-4">
            <StepHead n={2} title="Select Clients">
              <span className="ds-badge ds-badge-teal">{selectedClients.length} selected</span>
              {filteredClients.length > 0 && (
                <button
                  type="button"
                  onClick={selectAllClients}
                  className="ml-auto text-sm font-medium text-genz-teal hover:underline whitespace-nowrap"
                  title="Selects only the clients currently loaded below"
                >
                  {filteredClients.every(c => selectedClients.some(s => s._id === c._id)) ? 'Deselect loaded' : 'Select all loaded'}
                </button>
              )}
            </StepHead>

            <div className="relative mb-3">
              <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-genz-muted" size={16} />
              <input
                type="text"
                placeholder="Search clients..."
                value={clientSearch}
                onChange={(e) => setClientSearch(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 text-sm bg-genz-bg border border-genz-border rounded-xl text-genz-navy placeholder-genz-muted focus:outline-none focus:border-genz-teal transition-colors"
              />
            </div>

            {/* Selected Clients Tags */}
            {selectedClients.length > 0 && (
              <div className="flex flex-wrap gap-1.5 mb-3 p-2.5 bg-genz-bg rounded-xl">
                {selectedClients.map(client => (
                  <span
                    key={client._id}
                    className="inline-flex items-center gap-1 px-2.5 py-1 bg-genz-teal/20 text-genz-teal text-xs font-medium rounded-full max-w-full"
                    title={client.email ? `${client.fullName} — ${client.email}` : client.fullName}
                  >
                    <span className="truncate max-w-[220px]">
                      {client.fullName}{client.email ? <span className="opacity-70"> — {client.email}</span> : null}
                    </span>
                    <button type="button" onClick={() => toggleClient(client)} className="hover:text-genz-navy flex-shrink-0" aria-label={`Remove ${client.fullName}`}>
                      <X size={12} />
                    </button>
                  </span>
                ))}
              </div>
            )}

            {clientsLoading && filteredClients.length === 0 ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2" aria-busy="true" aria-label="Loading clients">
                {Array.from({ length: 6 }).map((_, i) => (
                  <div key={i} className="flex items-center gap-2.5 px-3 py-2 rounded-lg border border-genz-border bg-genz-bg animate-pulse">
                    <span className="w-7 h-7 rounded-md bg-genz-navy/10 flex-shrink-0" />
                    <div className="flex-1 min-w-0 space-y-1.5">
                      <div className="h-3 w-2/3 rounded bg-genz-navy/10" />
                      <div className="h-2.5 w-4/5 rounded bg-genz-navy/10" />
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-56 overflow-y-auto pr-1">
                {filteredClients.map(client => {
                  const isSelected = selectedClients.some(c => c._id === client._id);
                  return (
                    <button
                      key={client._id}
                      type="button"
                      onClick={() => toggleClient(client)}
                      className={`flex items-center gap-2.5 px-3 py-2 rounded-lg border text-left transition-all ${
                        isSelected
                          ? 'border-genz-teal bg-genz-teal/10'
                          : 'border-genz-border bg-genz-bg hover:border-genz-teal/50'
                      }`}
                      data-testid={`select-client-${client._id}`}
                    >
                      <span className={`w-7 h-7 rounded-md flex items-center justify-center text-white text-xs font-bold flex-shrink-0 ${isSelected ? '' : 'opacity-80'}`}
                            style={{ background: 'var(--gradient-cta)' }}>
                        {client.fullName?.charAt(0) || '?'}
                      </span>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-genz-navy truncate">{client.fullName}</p>
                        <p className="text-xs text-genz-muted truncate">{client.email}</p>
                      </div>
                      {isSelected && <CheckCircle2 size={16} className="text-genz-teal flex-shrink-0" />}
                    </button>
                  );
                })}
              </div>
            )}

            {!clientsLoading && filteredClients.length === 0 && (
              <p className="text-center text-sm text-genz-muted py-3">
                {clientSearch.trim() ? 'No clients match your search' : 'No active clients found'}
              </p>
            )}

            {!clientsLoading && filteredClients.length > 0 && (
              <div className="flex items-center justify-between gap-3 pt-3">
                <span className="text-[11px] text-genz-muted">
                  Showing {filteredClients.length}{clientTotal ? ` of ${clientTotal}` : ''} client{filteredClients.length === 1 ? '' : 's'}
                  {clientSearch.trim() ? ' matching your search' : ''}
                </span>
                {clientHasMore && (
                  <button
                    type="button"
                    onClick={loadMoreClients}
                    disabled={clientsLoadingMore}
                    className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-genz-border bg-genz-bg text-sm font-medium text-genz-navy hover:border-genz-teal/50 transition-colors disabled:opacity-50"
                    data-testid="load-more-clients"
                  >
                    {clientsLoadingMore && <Loader2 size={14} className="animate-spin" />}
                    {clientsLoadingMore ? 'Loading…' : 'Load more'}
                  </button>
                )}
              </div>
            )}
          </div>

          {/* Step 3: Set Duration */}
          <div className="ds-card p-4">
            <StepHead n={3} title="Set Access Duration" />

            <div className="flex flex-wrap gap-2 mb-3">
              {['7', '30', '90', '365'].map(days => (
                <button
                  key={days}
                  type="button"
                  onClick={() => handlePresetChange(days)}
                  className={`px-3.5 py-1.5 rounded-full text-sm font-medium transition-all ${
                    duration.preset === days
                      ? 'btn-grad'
                      : 'bg-genz-bg text-genz-muted border border-genz-border hover:border-genz-teal/50'
                  }`}
                >
                  {days === '7' && '1 Week'}
                  {days === '30' && '1 Month'}
                  {days === '90' && '3 Months'}
                  {days === '365' && '1 Year'}
                </button>
              ))}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div>
                <label className="flex items-center gap-1.5 text-sm font-medium text-genz-navy mb-1.5">
                  <Calendar size={14} className="text-genz-teal" />
                  Start Date
                </label>
                <input
                  type="date"
                  value={duration.startDate}
                  onChange={(e) => setDuration(prev => ({ ...prev, startDate: e.target.value }))}
                  className="w-full px-3.5 py-2.5 text-sm bg-genz-bg border border-genz-border rounded-xl text-genz-navy focus:outline-none focus:border-genz-teal transition-colors"
                  data-testid="start-date-input"
                />
              </div>
              <div>
                <label className="flex items-center gap-1.5 text-sm font-medium text-genz-navy mb-1.5">
                  <Calendar size={14} className="text-genz-teal" />
                  End Date
                </label>
                <input
                  type="date"
                  value={duration.endDate}
                  onChange={(e) => setDuration(prev => ({ ...prev, endDate: e.target.value, preset: '' }))}
                  min={duration.startDate}
                  className="w-full px-3.5 py-2.5 text-sm bg-genz-bg border border-genz-border rounded-xl text-genz-navy focus:outline-none focus:border-genz-teal transition-colors"
                  data-testid="end-date-input"
                />
              </div>
            </div>
          </div>

          {/* Submit */}
          <div className="flex items-center justify-end gap-3 pt-1">
            <button
              type="button"
              onClick={() => navigate('/admin/clients')}
              className="px-4 py-2.5 text-sm font-medium text-genz-muted hover:text-genz-navy transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={saving || selectedTools.length === 0 || selectedClients.length === 0}
              className="flex items-center gap-2 px-5 py-2.5 btn-grad rounded-xl text-sm font-bold hover:opacity-90 transition-opacity disabled:opacity-50"
              data-testid="bulk-assign-btn"
            >
              <Save size={16} />
              {saving
                ? 'Assigning...'
                : `Assign ${selectedTools.length} tool${selectedTools.length === 1 ? '' : 's'} to ${selectedClients.length} client${selectedClients.length === 1 ? '' : 's'}`}
            </button>
          </div>
        </form>
      </div>
    </AdminLayout>
  );
};

export default AdminBulkAssign;
